const body = $input.first().json.body;

const required = ['plateImageUrl', 'removalBrief', 'shotCode'];
for (const field of required) {
  if (!body[field] || String(body[field]).trim() === '') {
    throw new Error(`Validation failed: '${field}' is required.`);
  }
}

const data = {
  plateImageUrl:    body.plateImageUrl.trim(),
  removalBrief:     body.removalBrief.trim(),
  shotCode:         body.shotCode.trim(),
  sequenceCode:     body.sequenceCode?.trim() || body.shotCode.split('_')[0] || 'SEQ-000',
  projectId:        body.projectId?.trim() || 'PROJ-001',
  objectType:       body.objectType?.trim() || 'unwanted_object',  // wire | sign | crew | rig | general
  frameRange:       body.frameRange?.trim() || '1-100',
  frameRate:        body.frameRate || 24,
  qcThreshold:      body.qcThreshold || 0.85,   // 0-1, how clean must result be to auto-notify
  notionDatabaseId: body.notionDatabaseId?.trim() || null,
  supervisorEmail:  body.supervisorEmail?.trim() || null,
  requestTimestamp: new Date().toISOString()
};

return [{ json: data }];

const d = $input.first().json;
const p = d.removalBrief;

const objectInstructions = {
  'wire':    'Remove all visible wires, cables, and rigging hardware. Leave background clean and seamless.',
  'sign':    'Remove modern signage, replace with period-appropriate or clean background. Seamless integration.',
  'crew':    'Remove crew members, equipment, and production elements. Fill with natural background.',
  'rig':     'Remove camera rigs, support structures, and mechanical equipment. Restore background.',
  'general': 'Remove the specified unwanted elements. Restore background to clean natural state.'
};

const objectNote = objectInstructions[d.objectType] || objectInstructions['general'];
const techNote = `Shot: ${d.shotCode}, frames ${d.frameRange} at ${d.frameRate}fps. Seamless clean plate, no visible artifacts, photorealistic result.`;

const variations = [
  {
    variantId: 'CP-V1',
    passType:  'clean_plate',
    label:     'Clean Plate – Primary',
    safePrompt: JSON.stringify(`${p}. ${objectNote} ${techNote} Primary clean plate pass, maximum quality removal, background reconstruction must be invisible. Static locked-off camera --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId: 'CP-V2',
    passType:  'clean_plate_alt',
    label:     'Clean Plate – Alternative',
    safePrompt: JSON.stringify(`${p}. ${objectNote} ${techNote} Alternative interpretation of background reconstruction. Slightly different fill approach. Static locked-off camera --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId: 'CP-V3',
    passType:  'foreground_removal',
    label:     'Foreground Removal Pass',
    safePrompt: JSON.stringify(`${p}. Isolate and remove all foreground elements specified. Show only the clean background plate. ${techNote} Pure background extraction pass --duration 5 --camerafixed true`).slice(1,-1)
  },
  {
    variantId: 'CP-V4',
    passType:  'difference_preview',
    label:     'Difference Map Preview',
    safePrompt: JSON.stringify(`Visual difference map showing what was removed: highlight changed regions in bright color (red/yellow) against dark background. Show exact areas of removal for ${p}. ${techNote} QC reference pass --duration 5 --camerafixed true`).slice(1,-1)
  }
];

return variations.map(v => ({ json: { ...v, ...d } }));

const input = $input.first().json;

// Always use image-to-video since we need the plate image as reference
const body = {
  model: 'seedance-1-5-pro-251215',
  content: [
    { type: 'text', text: input.safePrompt },
    { type: 'image_url', image_url: { url: input.plateImageUrl } }
  ],
  generate_audio: false,
  ratio: 'adaptive',
  duration: 5,
  watermark: false
};

return [{
  json: {
    ...input,
    requestBody: JSON.stringify(body),
    mode: 'image_to_video'
  }
}];

const httpResult = $input.first().json;
const variantData = $('Build Clean Plate Request').first().json;
return [{ json: { ...variantData, id: httpResult.id, jobStatus: httpResult.status } }];

const input = $input.first().json;
const variantData = $('Merge Job ID + Metadata').first().json;

let videoUrl = null;
if (input.content && input.content.video_url) {
  videoUrl = input.content.video_url;
}
if (!videoUrl) {
  videoUrl = input.output_url || input.video_url || `URL not found. Job ID: ${input.id}`;
}

// QC Score — simulated here based on resolution and status
// In production this would be a real pixel comparison
const resolutionScore = input.resolution === '1080p' ? 1.0 : input.resolution === '720p' ? 0.85 : 0.7;
const qcScore = resolutionScore; // simplified QC
const qcPassed = qcScore >= (variantData.qcThreshold || 0.85);

const passIcons = {
  'clean_plate':        '🧹',
  'clean_plate_alt':    '🔄',
  'foreground_removal': '✂️',
  'difference_preview': '🔍'
};

return [{
  json: {
    variantId:        variantData.variantId,
    passType:         variantData.passType,
    passIcon:         passIcons[variantData.passType] || '🎬',
    label:            variantData.label,
    shotCode:         variantData.shotCode,
    sequenceCode:     variantData.sequenceCode,
    projectId:        variantData.projectId,
    videoUrl:         videoUrl,
    plateImageUrl:    variantData.plateImageUrl,
    removalBrief:     variantData.removalBrief,
    objectType:       variantData.objectType,
    frameRange:       variantData.frameRange,
    frameRate:        variantData.frameRate,
    notionDatabaseId: variantData.notionDatabaseId,
    supervisorEmail:  variantData.supervisorEmail,
    jobId:            input.id,
    resolution:       input.resolution,
    duration:         input.duration,
    qcScore:          qcScore,
    qcPassed:         qcPassed,
    qcThreshold:      variantData.qcThreshold,
    generatedAt:      new Date().toISOString(),
    tags: {
      asset_type:     'clean_plate',
      pass_type:      variantData.passType,
      object_type:    variantData.objectType,
      shot_code:      variantData.shotCode,
      frame_range:    variantData.frameRange,
      qc_passed:      qcPassed,
      qc_score:       qcScore,
      ai_generated:   true,
      review_status:  qcPassed ? 'auto_approved' : 'needs_review',
      workflow:       'clean_plate_generator'
    }
  }
}];

const items = $input.all();
const nukeItems = $('Generate Nuke Comp Script').all();

const passes = nukeItems.map((item) => {
  const d = item.json;
  const qcBadge = d.qcPassed ? '✅ Auto-Approved' : '⚠️ Needs Review';
  return `${d.passIcon} *${d.label}* (${d.variantId})\n> 🎬 <${d.videoUrl}|Watch Pass>\n> 🔍 QC Score: ${(d.qcScore * 100).toFixed(0)}% — ${qcBadge}\n> 📝 Nuke: ${d.nukeScriptName}\n> 📁 Clean Plates: ${d.folderStructure.cleanPlates}\n> 📅 ${d.generatedAt}`;
});

const first = nukeItems[0].json;
const allPassed = nukeItems.every(i => i.json.qcPassed);

return [{
  json: {
    shotCode:      first.shotCode,
    sequenceCode:  first.sequenceCode,
    objectType:    first.objectType,
    removalBrief:  first.removalBrief,
    passLines:     passes.join('\n\n'),
    totalPasses:   passes.length,
    allQcPassed:   allPassed,
    nukeScript:    first.nukeScript,
    nukeScriptName: first.nukeScriptName,
    folderStructure: first.folderStructure,
    generatedAt:   new Date().toISOString()
  }
}];

